def synthesizer_agent(state: BlackboardState) -> dict:
    """Combines hypotheses and evidence into a candidate solution."""
    if not state["hypotheses"] or not state["evidence"]:
        return {"turn": state["turn"] + 1, "last_agent": "synthesizer_agent"}

    hyp_text = "\n".join(f"- [{h.confidence:.0%}] {h.text}" for h in state["hypotheses"])
    ev_text = "\n".join(f"- {e.content} (re: {e.supports})" for e in state["evidence"])

    prompt = f"""Problem: {state['problem_statement']}

Hypotheses:
{hyp_text}

Evidence:
{ev_text}

Synthesize a solution. Reply as JSON: {{"solution": "...", "confidence": 0.85}}"""

    response = llm.invoke([
        SystemMessage(content="You are a synthesis agent."),
        HumanMessage(content=prompt)
    ])

    import json, re
    raw = re.search(r'\{.*?\}', response.content, re.DOTALL)
    result = json.loads(raw.group()) if raw else {}

    return {
        "solution": result.get("solution"),
        "confidence": result.get("confidence", 0.0),
        "last_agent": "synthesizer_agent",
        "turn": state["turn"] + 1,
    }

def validator_agent(state: BlackboardState) -> dict:
    """Checks whether the current solution is complete and correct."""
    if not state["solution"]:
        return {"turn": state["turn"] + 1, "last_agent": "validator_agent"}

    prompt = f"""Problem: {state['problem_statement']}
Proposed solution: {state['solution']}
Confidence: {state['confidence']:.0%}

Is this solution correct and complete? Reply: {{"valid": true/false, "reason": "..."}}"""

    response = llm.invoke([
        SystemMessage(content="You are a strict validator agent."),
        HumanMessage(content=prompt)
    ])

    import json, re
    raw = re.search(r'\{.*?\}', response.content, re.DOTALL)
    result = json.loads(raw.group()) if raw else {}

    done = result.get("valid", False) and state["confidence"] >= 0.8
    return {
        "done": done,
        "last_agent": "validator_agent",
        "turn": state["turn"] + 1,
    }

from langchain_anthropic import ChatAnthropic
from langchain_core.messages import SystemMessage, HumanMessage

controller_llm = ChatAnthropic(model="claude-haiku-4-5-20251001")

AGENTS = ["hypothesis_agent", "evidence_agent", "synthesizer_agent", "validator_agent"]

def llm_controller(state: BlackboardState) -> str:
    if state["done"] or state["turn"] >= MAX_TURNS:
        return "__end__"

    summary = f"""Blackboard state:
- Problem: {state['problem_statement']}
- Hypotheses: {len(state['hypotheses'])} (last: {state['hypotheses'][-1].text[:60] if state['hypotheses'] else 'none'})
- Evidence pieces: {len(state['evidence'])}
- Current solution: {state['solution'] or 'none'}
- Confidence: {state['confidence']:.0%}
- Turn: {state['turn']}/{MAX_TURNS}
- Last agent: {state['last_agent']}

Agents available: {', '.join(AGENTS)}
Which agent should run next to make the most progress?
Reply with ONLY the agent name, nothing else."""

    response = controller_llm.invoke([
        SystemMessage(content="You are an intelligent scheduler for a multi-agent system."),
        HumanMessage(content=summary)
    ])

    chosen = response.content.strip()
    if chosen not in AGENTS:
        # Fallback to rule-based if LLM returns an invalid agent
        return controller(state)
    return chosen
